-- Create "business_attachments" table
CREATE TABLE "business_attachments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "owner_type" character varying NOT NULL,
  "owner_id" bigint NOT NULL,
  "attachment_type" character varying NOT NULL DEFAULT 'evidence',
  "slot_key" character varying NULL,
  "file_name" character varying NOT NULL,
  "mime_type" character varying NOT NULL,
  "file_size" bigint NOT NULL,
  "sha256" character varying NOT NULL,
  "content" bytea NOT NULL,
  "uploaded_by" bigint NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "business_attachments_file_size_positive" CHECK (file_size > 0),
  CONSTRAINT "business_attachments_owner_type_allowed" CHECK ((owner_type)::text = ANY ((ARRAY['sales_order'::character varying, 'purchase_order'::character varying, 'outsourcing_order'::character varying, 'purchase_receipt'::character varying, 'quality_inspection'::character varying, 'shipment'::character varying, 'finance_fact'::character varying, 'production_fact'::character varying, 'outsourcing_fact'::character varying, 'product_sku'::character varying, 'bom_header'::character varying, 'workflow_task'::character varying])::text[]))
);
-- Create index "businessattachment_owner_type_owner_id" to table: "business_attachments"
CREATE INDEX "businessattachment_owner_type_owner_id" ON "business_attachments" ("owner_type", "owner_id");
-- Create index "businessattachment_owner_type_owner_id_created_at" to table: "business_attachments"
CREATE INDEX "businessattachment_owner_type_owner_id_created_at" ON "business_attachments" ("owner_type", "owner_id", "created_at");
-- Create index "businessattachment_sha256" to table: "business_attachments"
CREATE INDEX "businessattachment_sha256" ON "business_attachments" ("sha256");
-- Create index "businessattachment_uploaded_by" to table: "business_attachments"
CREATE INDEX "businessattachment_uploaded_by" ON "business_attachments" ("uploaded_by");
